var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"에써릴! 오버 드라이브!!","JPN":"イーサリアル！　オーバードライブ！！","ENG":"Ethereal! Overdrive!","TWN":"淩空！駕馭！！"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_DOOM","text":{"KOREA":"저것은! 빛의 날개를 펼치는 나이엘의 비기!","JPN":"あれは！　光の翼を広げるナイエルの秘技！","ENG":"By the North Star! Isn't that Naielle's secret move spreading the wings of light?!","TWN":"那是！展開光翼的奈爾秘技！"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_DOOM","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_DOOM","text":{"KOREA":"그 기동성은 3종 침식체도 따라오지 못할 정도!","JPN":"その速さは第3種侵食体も追いつけないほど！","ENG":"Not even a Category 3 can keep up with its speed!","TWN":"它的機動性可是快到連3類侵蝕體也看不到它的車尾燈！"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_DOOM","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"으아아악! 따라오지 마! 이 괴물 자식아!!","JPN":"うわああぁぁぁ！　ついてこないで！　この化け物！！","ENG":"Eeeek! Stop following me! You monster!!","TWN":"呃啊啊啊！不准過來！！你們這些怪物～～"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_DOOM","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_DOOM","text":{"KOREA":"과연! 도망치기에 최선의 기술이로군!","JPN":"さすがだな！　逃げるのに最善の技か！","ENG":"Aha! It is a skill optimized for a tactical retreat!","TWN":"厲害！不愧是最適合逃跑的技能！"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_DOOM","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"이 멍청아! 기술 설명은 됐으니까 빨리 탑이나 박살내!","JPN":"バカ！　いちいち説明はいいからはやく塔を壊して！","ENG":"You idiot! Enough with the commentary! Just smash the tower!","TWN":"喂！你現場轉播好了沒！快去毀掉那座塔啦！"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_DOOM","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_DOOM","text":{"KOREA":"알겠다, 동지여!","JPN":"うむ、同士よ！","ENG":"Very well, comrade!","TWN":"好的，夥伴！"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_DOOM","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_DOOM","text":{"KOREA":"흐으읍!","JPN":"ふうっ！","ENG":"Hrrmph!","TWN":"嘿咻！"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_DOOM","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_DOOM","text":{"KOREA":"무.","JPN":"こ","ENG":"You…","TWN":"給"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_HIT_ROCK_SMALL"},{"id":"L20_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_DOOM","text":{"KOREA":"너.","JPN":"わ","ENG":"Are…","TWN":"我"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_HIT_ROCK_BIG"},{"id":"L21_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_DOOM","text":{"KOREA":"져.","JPN":"れ","ENG":"Already…","TWN":"解"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_HIT_ROCK_BIG_02"},{"id":"L22_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_DOOM","text":{"KOREA":"라!","JPN":"ろ！","ENG":"Dead!","TWN":"體"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_DOOM","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_EXPLOSION_ENERGY_BIG_08"},{"id":"L27_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"서, 성공했나?","JPN":"せ、成功した！？","ENG":"D-did it work?","TWN":"成…成功了嗎？"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"으으으……. 최면 마술은 역시 후폭풍이 너무 심해…….","JPN":"むう……催眠術はやっぱり副反応がひどいね……","ENG":"Ugh… These hypnosis spells always have the worst after-effects…","TWN":"呼呼……催眠魔術的副作用真的很大……"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"앗! 저기 봐! 공간에 일어났던 균열들이 사라지나 봐!","JPN":"あっ、あれを見て！　空間の亀裂が消えてる！","ENG":"Oh! Look! The spatial rifts must be disappearing!","TWN":"哇！你看！那些空間的裂縫好像消失咧？"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_DARK_21"},{"id":"L32_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>코핀 오브 네헤모트. 동력 공급 중단.</color>","JPN":"<color=#ffd34c>コフィン・オブ・ネヘモト。動力供給中断。</color>","ENG":"<color=#ffd34c>Coffin of Nehemoth. Power supply interrupted.</color>","TWN":"<color=#ffd34c>科芬之貝赫莫特暫停供應動能。</color>"},"stage":{"bg":"CASTLE_03","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_SIREN"},{"id":"L33_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>비상 안전모드로 전환. 최소한의 시스템 유지를 제외한 모든 기능을 정지합니다.</color>","JPN":"<color=#ffd34c>非常安全モードに移行。最低限のシステム維持を除くすべての機能を停止します。</color>","ENG":"<color=#ffd34c>Switching to emergency safety mode. Shutting down all functions except those required for minimal system operation.</color>","TWN":"<color=#ffd34c>轉換成緊急安全模式。除維持基本系統運作外，其餘功能全部停止運作。</color>"},"stage":{"bg":"CASTLE_03","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L34_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>최소한의 시스템 유지를 제외한 모든 기능을 정지합니다.</color>","JPN":"<color=#ffd34c>最低限のシステム維持を除くすべての機能を停止します。</color>","ENG":"<color=#ffd34c>Shutting down all functions except those required for minimal system operation.</color>","TWN":"<color=#ffd34c>除維持基本系統運作外，其餘功能全部停止運作。</color>"},"stage":{"bg":"CASTLE_03","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"성공이야! 역시 이 탑이 엔진이었나 봐!","JPN":"成功した！　やっぱりこの塔がエンジンだったみたい！","ENG":"It worked! This tower must have been the engine!","TWN":"成功了！這座塔果然就是引擎沒錯！"},"stage":{"bg":"CASTLE_03","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"좋아할 때가 아니야! 뒤를 봐!","JPN":"喜んでいる場合じゃない！　後ろをみて！","ENG":"It's too early to celebrate! Look behind you!","TWN":"現在還不到開心的時候，你看後面！"},"stage":{"bg":"CASTLE_03","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"어?","JPN":"あれ？","ENG":"Huh?","TWN":"怎樣？"},"stage":{"bg":"CASTLE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"침식체야! 도망쳐!!","JPN":"侵食体よ！　逃げて！！","ENG":"It's a C.O.! Run!!","TWN":"有侵蝕體！！快跑！！"},"stage":{"bg":"CASTLE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"},{"id":"L47_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"나…… 살아 있나?","JPN":"私……生きてる？","ENG":"Am I… still alive?","TWN":"我……我還活著嗎？"},"stage":{"bg":"CASTLE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"다친 데는 없나?","JPN":"ケガはないか？","ENG":"Are you all right?","TWN":"有受傷嗎？"},"stage":{"bg":"CASTLE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"복장을 보니 카운터 아카데미 학생들인가 보군.","JPN":"服装からして、カウンターアカデミーの生徒のようだな。","ENG":"Your outfit suggests that you're from the Counter Academy.","TWN":"看你的穿著應該是學院的學生吧？"},"stage":{"bg":"CASTLE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"학생들이 올 만한 곳이 아닌데, 어떻게 된 거지?","JPN":"生徒が来れるような場所ではないが、どうやって来た？","ENG":"This is no place for students. What are you doing here?","TWN":"這裡不是學生該來的地方，你們怎麼會來這裡？"},"stage":{"bg":"CASTLE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"사, 살려 주셔서 감사합니다……?","JPN":"た、助けてくれてありがとうございます……！","ENG":"T-thank you for saving me…?","TWN":"謝…謝妳救我們……？"},"stage":{"bg":"CASTLE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"저희는 그러니까, 미나랑 같이 사람을 찾으러 왔는데요…….","JPN":"私たちは、えっと、ミナちゃんと一緒に人を探しに来て……","ENG":"Well, we're here to find someone with Mina…","TWN":"我們就和米娜一起來找人……"},"stage":{"bg":"CASTLE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"미나가 누구냐면 편입생인데 프로 용병이기도 하고…….","JPN":"あ、ミナちゃんは編入生でプロの傭兵なんですけど……","ENG":"Mina's a transfer student, who's also a professional mercenary…","TWN":"那米娜是誰呢？米娜是插班生，也是位很厲害的傭兵……"},"stage":{"bg":"CASTLE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하하, 많이 놀라셨나 보네요.","JPN":"ハハ、びっくりしたようですね。","ENG":"Haha, you must have been very startled.","TWN":"呵呵～你們似乎受到不小的驚嚇。"},"stage":{"bg":"CASTLE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"천천히 말씀하셔도 돼요. 이제 주변에 위험한 건 없으니까요.","JPN":"ゆっくりで大丈夫ですよ。この辺に危険なものはもうありません。","ENG":"You can slow down. The coast is clear now.","TWN":"慢慢說沒關係，你們已經安全了。"},"stage":{"bg":"CASTLE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그보다 말씀하셨던 미나란 분이, 코핀 컴퍼니의 유미나 양인가요?","JPN":"それより、さっき話に出てきたミナさんという方は、\\nコフィンカンパニーのヤナギ・ミナさんのことですか？","ENG":"Anyway, is this the same Mina as Yoo Mina of the Coffin Company?","TWN":"你剛說那位叫米娜的人，是科芬公司的劉米娜嗎？"},"stage":{"bg":"CASTLE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"아, 네! 미나를 알고 계세요?","JPN":"あ、はい！　お知り合いですか？","ENG":"Oh, yes! Do you know Mina?","TWN":"喔，對！你也認識米娜嗎？"},"stage":{"bg":"CASTLE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"네. 이래봬도 인연이 꽤 깊은 사이랍니다.","JPN":"はい、こう見えて緊密な関係っていうか、まあそんな感じです。","ENG":"Yes. In fact, we go way back.","TWN":"認識，而且還很熟呢！"},"stage":{"bg":"CASTLE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그보다 미나 양이 이곳이 와 있다, 라…….","JPN":"それより、ミナさんがここに来ている、と……","ENG":"In any case, if Mina is here…","TWN":"不過你說米娜也在這裡，那就表示……"},"stage":{"bg":"CASTLE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"저들의 목적은 처음부터 미나 양을 끌어들이는 것이었군요.","JPN":"彼らの目的は最初からミナさんを巻き込むことでしたね。","ENG":"Their goal must have been to lure Mina here in the first place.","TWN":"對方從一開始的目標就是米娜。"},"stage":{"bg":"CASTLE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"아무래도 함정에 빠진 모양이네요. 스승님.","JPN":"どうやら罠だったようです、師匠。","ENG":"It seems like she's fallen for a trap, Master.","TWN":"師父，我們似乎是掉入對方的陷阱了。"},"stage":{"bg":"CASTLE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"상황은 달라지지 않았다.","JPN":"状況は変わらない。","ENG":"Nothing's changed.","TWN":"我們的目標沒變。"},"stage":{"bg":"CASTLE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"공간 균열 때문에 시간을 너무 지체했어. 더 늦기 전에 주시윤이 있는 곳으로 돌입한다.","JPN":"空間亀裂のせいで時間を使ってしまった。手遅れになる前にアキヤマがいる場所に突入する。","ENG":"We lost too much time because of the spatial rift. We'll head right to where Shiyoon is before it's too late.","TWN":"前面已經因為空間裂縫的關係而浪費太多時間，現在要趕快進入周時雲在的地方！"},"stage":{"bg":"CASTLE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"바로 그 공간 균열 때문에 용인의 흔적은 끊어진 지 오래입니다.","JPN":"まさにその空間亀裂のせいで龍人の痕跡はとっくに消えています。","ENG":"But because of that spatial rift, the Dragonoid's tracks have vanished.","TWN":"龍人的線索也因為空間裂縫的關係而斷掉。"},"stage":{"bg":"CASTLE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"여기를 다 뒤지려면 시간이 꽤 걸릴 텐데요?","JPN":"ここを全て探すにはかなりの時間を要すると思いますが。","ENG":"It's going to take quite a while if we search this entire place.","TWN":"翻遍這裡要花不少時間喔？"},"stage":{"bg":"CASTLE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"여기는 서윤, 제 통신이 들리시나요?","JPN":"こちらアオイ・シズカ、聞こえますか？","ENG":"Seo Yoon here. Do you copy?","TWN":"我是徐芸，有聽到我的聲音嗎？"},"stage":{"bg":"CASTLE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"알트 소대장? 너도 여기 와 있었나?","JPN":"アルト小隊長？　お前もここに来ていたのか？","ENG":"ALT Squad Commander? You’re here too?","TWN":"阿爾特小隊長？你也來啦？"},"stage":{"bg":"CASTLE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"역시, 힐데 소대장님이셨군요.","JPN":"やはり、ヒルデ小隊長でしたか。","ENG":"Just as I thought. It's you, Commander Hilde.","TWN":"果然是你，希爾德小隊長。"},"stage":{"bg":"CASTLE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"갑자기 공간 균열이 사라지면서 근거리 통신이 가능해졌어요.","JPN":"急に空間亀裂が消えて、近距離通信が可能になりました。","ENG":"When the spatial rift disappeared, close range comms suddenly came back online.","TWN":"空間裂縫消失後，突然可以近距離通訊，"},"stage":{"bg":"CASTLE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"통신망에 소대장님의 신호가 잡혀서 혹시나 했는데…… 정말 다행이네요.","JPN":"通信レーダーに小隊長の信号が現れたので、もしかしてと思ったら…… 本当に幸いでした。","ENG":"Imagine my surprise when I found your signal in the network… I'm glad I got in touch.","TWN":"通訊網發現到小隊長的訊號，我就猜會不會是你……太好了，真的是你！"},"stage":{"bg":"CASTLE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"오, 무사하셨네요. 서윤 양.","JPN":"無事でしたか、アオイ・シズカさん。","ENG":"Oh, you've been alive and well. Seo Yoon.","TWN":"哦！徐芸你還活得好好的呢。"},"stage":{"bg":"CASTLE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"다시 얼굴을 보니 반가운데요?","JPN":"またお会いできて嬉しいです。","ENG":"It's a pleasure to see you again.","TWN":"很開心又見到你～"},"stage":{"bg":"CASTLE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"당신! 그때 그 납치범이잖아? 미안하지만 난 하나도 반갑지 않은걸?","JPN":"あなた！　あの時の誘拐犯じゃない！　悪いけどこっちは全然嬉しくないわ！","ENG":"You! You're that abductor from before! I can't say I'm pleased to see you at all!","TWN":"你！你不就是那時候的綁架犯嗎！不好意思喔，看到你我一點都不覺得開心。"},"stage":{"bg":"CASTLE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그러니까 그건 납치가 아니라 합의하에 진행한…… 아니, 뭐 마음대로 생각하시죠.","JPN":"だからそれは誘拐じゃなくて、合意の下で行われた……いや、まあ好きに考えてください。","ENG":"I wouldn't call that an abduction so much as a mutually agreed upon… Oh, whatever. Think of it what you'd like.","TWN":"那個不是綁架，是照協議進行的……沒事，你說是就是吧！"},"stage":{"bg":"CASTLE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L32_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"누가 수연이 부하직원 아니랄까 봐 말귀가 안 통하는 건 똑같군요.","JPN":"やはりキズナの部下らしく、話が通じないのは同じですね。","ENG":"Of course she works for Sooyeon. It's like talking to a wall.","TWN":"怕人家不知道你是秀妍的員工嗎？講話的語氣跟她一模一樣。"},"stage":{"bg":"CASTLE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"다치지 않은 것 같아 다행이에요, 미카. 나이엘 학생.","JPN":"ケガがないようで幸いです。ミカさん、ナイエルさん。","ENG":"I'm glad you two are unharmed, Mika, Naielle.","TWN":"米卡、奈爾同學，你們沒事就好。"},"stage":{"bg":"CASTLE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L36_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"둘이서 큰일을 해냈어요. 아카데미의 일원으로서 자랑스럽습니다.","JPN":"二人ともお見事です。アカデミーの一員として誇りに思います。","ENG":"You two have accomplished a remarkable feat. I'm so proud to have you as fellow students of the Academy.","TWN":"你們兩個完成了一件很了不起的事呢，身為學院的一員我感到很驕傲。"},"stage":{"bg":"CASTLE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L37_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"학생회장님! 역시 무사하셨네요!","JPN":"生徒会長！　やっぱり無事だったんですね！","ENG":"\\tStudent President! I knew you'd make it!","TWN":"學生會長！太好了，你也沒事！"},"stage":{"bg":"CASTLE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"아 참, 그 황태자란 사람은요?","JPN":"あ、あの皇太子という人は？","ENG":"By the way, happened to that prince guy?","TWN":"對了，那個叫皇太子的傢伙呢？"},"stage":{"bg":"CASTLE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"저희가 하급 침식체와 싸우는 모습을 관망하다가 방금 전 어딘가로 사라졌어요.","JPN":"私たちが下級侵食体と戦う様子を観ていたようですが、先ほどどこかに消えました。","ENG":"He was watching us fight the lower ranking C.O.s before disappearing somewhere just now.","TWN":"他原本在一旁看我們和那些低階侵蝕體戰鬥，後來不知道消失去哪裡了。"},"stage":{"bg":"CASTLE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"정황상 미나 양이 있는 곳으로 갔을 가능성이 커요.","JPN":"状況から考えるとミナさんがいる場所に向かった可能性が高いです。","ENG":"It's most likely that he's headed for where Mina is.","TWN":"照情況看來，應該是去了米娜所在的地方。"},"stage":{"bg":"CASTLE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그, 그러면 이번엔 미나가 위험하겠네요?","JPN":"つ、つまり今度はミナちゃんが危ないってことですね。","ENG":"Oh no… Does that mean Mina's in danger now?","TWN":"那這樣，米娜豈不是會有危險？"},"stage":{"bg":"CASTLE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"알트 소대장, 신입은 어디로 향했지?","JPN":"アルト小隊長、新人はどこへ行ったんだ？","ENG":"ALT Commander, where did the rookie go?","TWN":"阿爾特小隊長，新人的方向是往哪裡？"},"stage":{"bg":"CASTLE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"주시윤 선배를 구하기 위해 먼저 중심부로 돌입했습니다.","JPN":"アキヤマ先輩を救出するために、先に中心部に向いました。","ENG":"She headed for the central area first to save Shiyoon.","TWN":"她先進入中心的位置去救周時雲前輩。"},"stage":{"bg":"CASTLE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"좌표를 보내 드릴게요. 저희도 그쪽으로 가겠습니다.","JPN":"座標をお送りします。私たちもそちらに向かいます。","ENG":"I'll send you the coordinates. We'll be right there as well.","TWN":"我把座標給你，我們也要去那裡。"},"stage":{"bg":"CASTLE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"알겠다. 미리 말해 두는데 놈들과 마주쳐도 교전은 반드시 피하도록.","JPN":"わかった。先に言っておくが、奴らと出くわしても交戦は必ず避けるように。","ENG":"Acknowledged. Just to be clear, avoid engagement with them even if you make contact.","TWN":"好，我先把話說在前頭，萬一碰到那些傢伙，一定要避免交手。"},"stage":{"bg":"CASTLE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"너희들이 상대할 수 있는 적이 아니다. 내가 도착하기를 기다려라.","JPN":"お前たちが相手にできる敵ではない。私の到着を待て。","ENG":"You're no match for them. Wait for my arrival.","TWN":"他們不是你們能應付的，要等我到。"},"stage":{"bg":"CASTLE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"그런 거라면 이미 잘 알고 있어요.","JPN":"そんなことならもうわかっています。","ENG":"Copy. I'm already well aware of that.","TWN":"這點我們自己也很清楚。"},"stage":{"bg":"CASTLE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"최대한 노력해 보겠습니다. 이만.","JPN":"最大限努力してみます、それでは。","ENG":"I'll try my best. Over and out.","TWN":"我們會努力的，走囉！"},"stage":{"bg":"CASTLE_03","bgm":"THEMA_COFFIN_CUT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};